"use server";

import { MedicalCertificate, Prescription, LabResult } from '@/types';

interface SendPrescriptionInput {
  appointmentId: string;
  patientId: string;
  doctorId: string;
  diagnosis: string;
  medications: string;
  instructions: string;
}

interface SendLabInput {
  appointmentId: string;
  patientId: string;
  doctorId: string;
  testName: string;
  notes: string;
}

interface SendCertificateInput {
  appointmentId: string;
  patientId: string;
  doctorId: string;
  purpose: string;
  diagnosis: string;
  restDays: number;
}

export async function endConsult(appointmentId: string) {
  return {
    appointmentId,
    endedAt: new Date().toISOString(),
    transcript: 'Consultation ended. Summary recorded by doctor.',
  };
}

export async function sendPrescription(input: SendPrescriptionInput): Promise<Prescription> {
  const meds = input.medications
    .split('\n')
    .filter(Boolean)
    .map((line) => ({
      name: line.split('-')[0]?.trim() || line.trim(),
      dosage: '500mg',
      frequency: 'Once daily',
      duration: '7 days',
    }));

  return {
    id: `rx-${Date.now()}`,
    appointmentId: input.appointmentId,
    patientId: input.patientId,
    doctorId: input.doctorId,
    date: new Date().toISOString().split('T')[0],
    diagnosis: input.diagnosis || 'General Consultation',
    medications: meds.length ? meds : [
      { name: input.medications || 'Paracetamol', dosage: '500mg', frequency: 'Every 6 hours', duration: '3 days' },
    ],
    instructions: input.instructions || 'Take with food. Stay hydrated.',
    validUntil: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    isDigital: true,
  };
}

export async function sendLabRequest(input: SendLabInput): Promise<LabResult> {
  return {
    id: `lab-${Date.now()}`,
    patientId: input.patientId,
    doctorId: input.doctorId,
    appointmentId: input.appointmentId,
    testName: input.testName || 'Laboratory Test',
    testType: 'Lab Request',
    date: new Date().toISOString().split('T')[0],
    status: 'pending',
    notes: input.notes,
    laboratory: 'NowServing Partner Lab',
  };
}

export async function sendMedicalCertificate(input: SendCertificateInput): Promise<MedicalCertificate> {
  const today = new Date();
  const validFrom = today.toISOString().split('T')[0];
  const validUntilDate = new Date(today);
  validUntilDate.setDate(today.getDate() + (input.restDays || 1));

  return {
    id: `cert-${Date.now()}`,
    patientId: input.patientId,
    doctorId: input.doctorId,
    date: validFrom,
    purpose: input.purpose || 'Medical Certificate',
    diagnosis: input.diagnosis || 'General Consultation',
    restDays: input.restDays || 1,
    validFrom,
    validUntil: validUntilDate.toISOString().split('T')[0],
  };
}
