"use client";

import { useState } from 'react';
import { FileText, ClipboardList, FileSignature } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Card, CardContent } from '@/components/ui/card';

type DocType = 'prescription' | 'lab' | 'certificate';

interface DocumentComposerProps {
  onSendPrescription: (payload: { diagnosis: string; medications: string; instructions: string }) => void;
  onSendLab: (payload: { testName: string; notes: string }) => void;
  onSendCertificate: (payload: { purpose: string; diagnosis: string; restDays: number }) => void;
}

export default function DocumentComposer({
  onSendPrescription,
  onSendLab,
  onSendCertificate,
}: DocumentComposerProps) {
  const [type, setType] = useState<DocType>('prescription');
  const [diagnosis, setDiagnosis] = useState('');
  const [medications, setMedications] = useState('');
  const [instructions, setInstructions] = useState('');
  const [testName, setTestName] = useState('');
  const [labNotes, setLabNotes] = useState('');
  const [purpose, setPurpose] = useState('');
  const [restDays, setRestDays] = useState('3');

  return (
    <Card>
      <CardContent className="p-4 space-y-4">
        <div className="flex gap-2 flex-wrap">
          <Button
            size="sm"
            variant={type === 'prescription' ? 'default' : 'outline'}
            className="gap-1.5"
            onClick={() => setType('prescription')}
          >
            <FileText className="h-4 w-4" />
            E-Prescription
          </Button>
          <Button
            size="sm"
            variant={type === 'lab' ? 'default' : 'outline'}
            className="gap-1.5"
            onClick={() => setType('lab')}
          >
            <ClipboardList className="h-4 w-4" />
            Lab Request
          </Button>
          <Button
            size="sm"
            variant={type === 'certificate' ? 'default' : 'outline'}
            className="gap-1.5"
            onClick={() => setType('certificate')}
          >
            <FileSignature className="h-4 w-4" />
            Medical Certificate
          </Button>
        </div>

        {type === 'prescription' && (
          <div className="space-y-3">
            <Input placeholder="Diagnosis" value={diagnosis} onChange={(e) => setDiagnosis(e.target.value)} />
            <Textarea
              placeholder="Medications (e.g., Amoxicillin 500mg - 3x daily for 7 days)"
              value={medications}
              onChange={(e) => setMedications(e.target.value)}
            />
            <Textarea
              placeholder="Additional instructions"
              value={instructions}
              onChange={(e) => setInstructions(e.target.value)}
            />
            <Button onClick={() => onSendPrescription({ diagnosis, medications, instructions })}>
              Send Prescription
            </Button>
          </div>
        )}

        {type === 'lab' && (
          <div className="space-y-3">
            <Input placeholder="Test name (e.g., CBC, Lipid Profile)" value={testName} onChange={(e) => setTestName(e.target.value)} />
            <Textarea placeholder="Notes / instructions" value={labNotes} onChange={(e) => setLabNotes(e.target.value)} />
            <Button onClick={() => onSendLab({ testName, notes: labNotes })}>Send Lab Request</Button>
          </div>
        )}

        {type === 'certificate' && (
          <div className="space-y-3">
            <Input placeholder="Purpose (e.g., Sick leave)" value={purpose} onChange={(e) => setPurpose(e.target.value)} />
            <Input placeholder="Diagnosis" value={diagnosis} onChange={(e) => setDiagnosis(e.target.value)} />
            <Input
              type="number"
              placeholder="Rest days"
              value={restDays}
              onChange={(e) => setRestDays(e.target.value)}
            />
            <Button onClick={() => onSendCertificate({ purpose, diagnosis, restDays: Number(restDays || 0) })}>
              Send Certificate
            </Button>
          </div>
        )}
      </CardContent>
    </Card>
  );
}
